#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include "ulid.h"
int
main(int argc, char *argv[])
{
	char ulid[27] = { 0 };
	int c;
	long n = 1;
	int tflag = 0;
        while ((c = getopt(argc, argv, "n:t")) != -1)
	        switch (c) {
	        case 'n': n = atol(optarg); break;
	        case 't': tflag = 1; break;
	        }
	if (tflag) {
		char *line = 0;
		size_t linelen = 0;
		setvbuf(stdout, 0, _IOLBF, 0);
		while (getdelim(&line, &linelen, '\n', stdin) != -1) {
			ulidgen_r(ulid);
			printf("%s %s", ulid, line);
		}
	} else {
		for (long i = 0; i < n; i++) {
			ulidgen_r(ulid);
			puts(ulid);
		}
	}
	fflush(0);
	exit(!!ferror(stdout));
}
